const express = require('express');
const session = require('express-session');
const bodyParser = require('body-parser');
const twilio = require('twilio');

const app = express();
app.use(bodyParser.urlencoded({ extended: false }));
app.use(session({ secret: 'secret-key', resave: false, saveUninitialized: true }));

const accountSid = 'YOUR_TWILIO_ACCOUNT_SID';
const authToken = 'YOUR_TWILIO_AUTH_TOKEN';
const client = new twilio(accountSid, authToken);

function generateRandomCode() {
  return Math.floor(100000 + Math.random() * 900000);
}

app.get('/login', (req, res) => {
  const code = generateRandomCode();
  req.session.code = code;
  client.messages.create({
    body: `Your authentication code is: ${code}`,
    to: 'USER_PHONE_NUMBER',
    from: 'YOUR_TWILIO_PHONE_NUMBER'
  })
  .then(message => {
    console.log(message.sid);
    res.send('Authentication code sent to your phone.');
  })
  .catch(err => {
    console.error(err);
    res.status(500).send('Failed to send authentication code.');
  });
});

app.post('/verify', (req, res) => {
  const userCode = req.body.code;
  if (req.session.code == userCode) {
    res.send('Authentication successful!');
  } else {
    res.status(401).send('Authentication failed. Please try again.');
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});